'use client';

import { useSession } from 'next-auth/react';
import { useRouter } from 'next/navigation';
import { useEffect, useState, useRef } from 'react';
import Link from 'next/link';
import {
  ChevronRight,
  Home,
  Clock,
  Users,
  Search,
  Loader2,
  Save,
  Upload,
  X,
  AlertTriangle,
  CheckCircle2,
  FileSpreadsheet,
  LayoutGrid,
  Table2,
  TrendingUp,
  Printer,
  Filter
} from 'lucide-react';
import { canAccessClinical, canEditClinical, type Role } from '@/lib/permissions';
import { useToast } from '@/components/Toast';
import { PageErrorBoundary } from '@/components/PageErrorBoundary';
import Breadcrumbs from '@/components/Breadcrumbs';
import { apiFetch, isAuthError } from '@/lib/fetch-utils';

interface Student {
  id: string;
  first_name: string;
  last_name: string;
  email: string | null;
  status?: string | null;
}

interface CohortOption {
  id: string;
  cohort_number: number;
  program: { abbreviation: string };
  start_date?: string | null;
  expected_end_date?: string | null;
}

// Wide table structure - one row per student with all hours/shifts
interface StudentHours {
  id?: string;
  student_id: string;
  first_name?: string;
  last_name?: string;
  cohort_id?: string;
  psych_hours: number;
  psych_shifts: number;
  ed_hours: number;
  ed_shifts: number;
  icu_hours: number;
  icu_shifts: number;
  ob_hours: number;
  ob_shifts: number;
  or_hours: number;
  or_shifts: number;
  peds_ed_hours: number;
  peds_ed_shifts: number;
  peds_icu_hours: number;
  peds_icu_shifts: number;
  ems_field_hours: number;
  ems_field_shifts: number;
  cardiology_hours: number;
  cardiology_shifts: number;
  ems_ridealong_hours: number;
  ems_ridealong_shifts: number;
  total_hours: number;
  total_shifts: number;
}

// Hour requirements for each category
const HOUR_REQUIREMENTS: Record<string, number> = {
  psych_hours: 12,
  ed_hours: 132,
  icu_hours: 12,
  ob_hours: 24,
  or_hours: 36,
  peds_ed_hours: 36,
  peds_icu_hours: 12,
  ems_field_hours: 24,  // Elective/Misc
  cardiology_hours: 0,  // CCL - no requirement
  ems_ridealong_hours: 0,  // EMS ride-alongs - no requirement
};

const TOTAL_REQUIRED_HOURS = 290;

// Department requirements used for progress visualization (required > 0 only)
const DEPT_PROGRESS_ITEMS = [
  { key: 'psych_hours', label: 'Psych', required: 12, color: 'bg-purple-500' },
  { key: 'ed_hours', label: 'ED', required: 132, color: 'bg-blue-500' },
  { key: 'icu_hours', label: 'ICU', required: 12, color: 'bg-cyan-500' },
  { key: 'ob_hours', label: 'OB', required: 24, color: 'bg-pink-500' },
  { key: 'or_hours', label: 'OR', required: 36, color: 'bg-indigo-500' },
  { key: 'peds_ed_hours', label: 'Peds ED', required: 36, color: 'bg-orange-500' },
  { key: 'peds_icu_hours', label: 'Peds ICU', required: 12, color: 'bg-teal-500' },
  { key: 'ems_field_hours', label: 'Elective', required: 24, color: 'bg-green-500' },
] as const;

// Department columns configuration - maps to wide table columns
// CCL in UI = cardiology in DB
const DEPT_COLUMNS = [
  { key: 'psych', label: 'Psych', fullName: 'Behavioral Health', hoursField: 'psych_hours' as const, shiftsField: 'psych_shifts' as const, required: 12 },
  { key: 'ed', label: 'ED', fullName: 'Emergency Room', hoursField: 'ed_hours' as const, shiftsField: 'ed_shifts' as const, required: 132 },
  { key: 'icu', label: 'ICU', fullName: 'Intensive Care Unit', hoursField: 'icu_hours' as const, shiftsField: 'icu_shifts' as const, required: 12 },
  { key: 'ob', label: 'OB', fullName: 'Labor & Delivery', hoursField: 'ob_hours' as const, shiftsField: 'ob_shifts' as const, required: 24 },
  { key: 'or', label: 'OR', fullName: 'Inpatient', hoursField: 'or_hours' as const, shiftsField: 'or_shifts' as const, required: 36 },
  { key: 'peds_ed', label: 'Peds ED', fullName: 'Pediatric ED', hoursField: 'peds_ed_hours' as const, shiftsField: 'peds_ed_shifts' as const, required: 36 },
  { key: 'peds_icu', label: 'Peds ICU', fullName: 'Pediatric ICU', hoursField: 'peds_icu_hours' as const, shiftsField: 'peds_icu_shifts' as const, required: 12 },
  { key: 'ems_field', label: 'Elective', fullName: 'EMS Field / Elective', hoursField: 'ems_field_hours' as const, shiftsField: 'ems_field_shifts' as const, required: 24 },
  { key: 'cardiology', label: 'CCL', fullName: 'Cardiac Cath Lab', hoursField: 'cardiology_hours' as const, shiftsField: 'cardiology_shifts' as const, required: 0 },
  { key: 'ems_ridealong', label: 'EMS', fullName: 'EMS Ride-Along', hoursField: 'ems_ridealong_hours' as const, shiftsField: 'ems_ridealong_shifts' as const, required: 0 },
] as const;

interface ImportPreviewRow {
  name: string;
  matchedStudent: Student | null;
  similarNames: string[];  // Suggestions for unmatched names
  data: Partial<StudentHours>;
  manualMatch?: string;  // For manual matching by user
  isInactive?: boolean;  // True when name had asterisk (*) prefix in Platinum export
}

type ViewMode = 'dashboard' | 'detailed';

export default function ClinicalHoursTrackerPage() {
  const { data: session, status } = useSession();
  const router = useRouter();
  const fileInputRef = useRef<HTMLInputElement>(null);
  const toast = useToast();

  const [allCohorts, setAllCohorts] = useState<CohortOption[]>([]);
  const [cohorts, setCohorts] = useState<CohortOption[]>([]);
  const [students, setStudents] = useState<Student[]>([]);
  const [hoursData, setHoursData] = useState<StudentHours[]>([]);
  const [loading, setLoading] = useState(true);
  const [saving, setSaving] = useState<string | null>(null);
  const [userRole, setUserRole] = useState<Role | null>(null);

  const [selectedProgram, setSelectedProgram] = useState<string>('Paramedic');
  const [selectedCohort, setSelectedCohort] = useState('');
  const [searchQuery, setSearchQuery] = useState('');
  const [editingCell, setEditingCell] = useState<string | null>(null);
  const [editValue, setEditValue] = useState({ shifts: 0, hours: 0 });
  const [viewMode, setViewMode] = useState<ViewMode>('dashboard');
  const [showInactive, setShowInactive] = useState(false);

  const [fetchError, setFetchError] = useState<string | null>(null);

  // Import modal state
  const [showImportModal, setShowImportModal] = useState(false);
  const [importPreview, setImportPreview] = useState<ImportPreviewRow[]>([]);
  const [importing, setImporting] = useState(false);
  const [importError, setImportError] = useState<string | null>(null);

  useEffect(() => {
    if (status === 'unauthenticated') {
      router.push('/auth/signin');
    }
  }, [status, router]);

  useEffect(() => {
    if (session) {
      fetchInitialData();
    }
  }, [session]);

  useEffect(() => {
    if (selectedCohort) {
      fetchCohortData();
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedCohort]);

  useEffect(() => {
    if (selectedCohort) {
      fetchCohortData(showInactive);
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [showInactive]);

  // ESC key to close import modal
  useEffect(() => {
    if (!showImportModal) return;
    const handleEsc = (e: KeyboardEvent) => {
      if (e.key === 'Escape') {
        setShowImportModal(false);
        setImportPreview([]);
      }
    };
    document.addEventListener('keydown', handleEsc);
    return () => document.removeEventListener('keydown', handleEsc);
  }, [showImportModal]);

  // Helper: check if an abbreviation belongs to the Paramedic program
  const isParamedicAbbrev = (abbrev: string | undefined): boolean => {
    if (!abbrev) return false;
    const a = abbrev.toUpperCase();
    return a === 'PMD' || a === 'PM' || a === 'PARAMEDIC';
  };

  // Helper: check if an abbreviation matches the selected program filter
  const matchesProgram = (abbrev: string | undefined, program: string): boolean => {
    if (program === 'All') return true;
    if (program === 'Paramedic') return isParamedicAbbrev(abbrev);
    if (!abbrev) return false;
    return abbrev.toUpperCase() === program.toUpperCase();
  };

  // When program filter changes, re-filter cohorts and auto-select first match
  useEffect(() => {
    if (allCohorts.length === 0) return;
    const filtered = selectedProgram === 'All'
      ? allCohorts
      : allCohorts.filter(c => matchesProgram(c.program?.abbreviation, selectedProgram));
    setCohorts(filtered);
    if (filtered.length > 0) {
      setSelectedCohort(filtered[0].id);
    } else {
      setSelectedCohort('');
    }
  // eslint-disable-next-line react-hooks/exhaustive-deps
  }, [selectedProgram, allCohorts]);

  const fetchInitialData = async () => {
    setLoading(true);
    setFetchError(null);
    try {
      const userData = await apiFetch('/api/instructor/me');
      if (userData.success && userData.user) {
        setUserRole(userData.user.role);
        if (!canAccessClinical(userData.user.role)) {
          router.push('/');
          return;
        }
      }

      const cohortsData = await apiFetch('/api/lab-management/cohorts?activeOnly=false');
      if (cohortsData.success) {
        const fetched: CohortOption[] = cohortsData.cohorts || [];
        setAllCohorts(fetched);
        // Default to Paramedic program filter
        const paramedicCohorts = fetched.filter(c =>
          isParamedicAbbrev(c.program?.abbreviation)
        );
        const filtered = paramedicCohorts.length > 0 ? paramedicCohorts : fetched;
        setCohorts(filtered);
        if (filtered.length > 0) {
          setSelectedCohort(filtered[0].id);
        }
      }
    } catch (error: any) {
      console.error('Error fetching data:', error);
      if (isAuthError(error)) {
        setFetchError('You are not authorized to view this page. Please sign in.');
      } else {
        setFetchError(error?.message || 'Failed to load data. Please refresh the page.');
      }
    }
    setLoading(false);
  };

  const fetchCohortData = async (fetchInactive?: boolean) => {
    try {
      const includeInactive = fetchInactive !== undefined ? fetchInactive : showInactive;
      const [studentsData, hoursDataRes] = await Promise.all([
        apiFetch(`/api/students?cohortId=${selectedCohort}&activeOnly=${!includeInactive}`),
        apiFetch(`/api/clinical/hours?cohortId=${selectedCohort}&activeOnly=${!includeInactive}`),
      ]);

      if (studentsData.success) setStudents(studentsData.students || []);
      if (hoursDataRes.success) setHoursData(hoursDataRes.hours || []);
    } catch (error: any) {
      console.error('Error fetching cohort data:', error);
      if (!isAuthError(error)) {
        toast.error(error?.message || 'Failed to load cohort data');
      }
    }
  };

  const getStudentHours = (studentId: string): StudentHours | null => {
    return hoursData.find(h => h.student_id === studentId) || null;
  };

  // Get completion status color for a cell
  const getCompletionColor = (current: number, required: number): string => {
    if (required === 0) return 'bg-gray-100 dark:bg-gray-700'; // No requirement
    const percentage = (current / required) * 100;
    if (percentage >= 100) return 'bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300';
    if (percentage >= 50) return 'bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-300';
    return 'bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300';
  };

  // Get progress bar color
  const getProgressColor = (percentage: number): string => {
    if (percentage >= 100) return 'bg-green-500';
    if (percentage >= 50) return 'bg-yellow-500';
    return 'bg-red-500';
  };

  // Calculate cohort summary stats
  const getCohortStats = () => {
    const totalStudents = students.length;
    let completedCount = 0;
    let totalPercentage = 0;

    students.forEach(student => {
      const hours = getStudentHours(student.id);
      const studentTotal = hours?.total_hours || 0;
      const percentage = Math.min((studentTotal / TOTAL_REQUIRED_HOURS) * 100, 100);
      totalPercentage += percentage;
      if (studentTotal >= TOTAL_REQUIRED_HOURS) {
        completedCount++;
      }
    });

    return {
      totalStudents,
      completedCount,
      averagePercentage: totalStudents > 0 ? Math.round(totalPercentage / totalStudents) : 0
    };
  };

  // Get per-department average hours across all students
  const getDeptAvgHours = () => {
    if (students.length === 0) return {} as Record<string, number>;
    const totals: Record<string, number> = {};
    DEPT_PROGRESS_ITEMS.forEach(dept => {
      let sum = 0;
      students.forEach(s => {
        const h = getStudentHours(s.id);
        sum += (h?.[dept.key as keyof StudentHours] as number) || 0;
      });
      totals[dept.key] = sum / students.length;
    });
    return totals;
  };

  // Calculate cohort-level pace info
  const getPaceInfo = () => {
    const cohortData = allCohorts.find(c => c.id === selectedCohort);
    const startDate = cohortData?.start_date ? new Date(cohortData.start_date) : null;
    const endDate = cohortData?.expected_end_date ? new Date(cohortData.expected_end_date) : null;
    const now = new Date();

    // Total hours earned across all students
    let totalEarned = 0;
    students.forEach(s => {
      const h = getStudentHours(s.id);
      totalEarned += h?.total_hours || 0;
    });
    const avgEarned = students.length > 0 ? totalEarned / students.length : 0;

    // Weeks elapsed since start
    let weeksElapsed = 0;
    let totalWeeks = 0;
    let proportionalHours = 0;

    if (startDate) {
      const msPerWeek = 7 * 24 * 60 * 60 * 1000;
      weeksElapsed = Math.max(0, (now.getTime() - startDate.getTime()) / msPerWeek);
      if (endDate) {
        totalWeeks = Math.max(1, (endDate.getTime() - startDate.getTime()) / msPerWeek);
        const elapsed = Math.min(weeksElapsed, totalWeeks);
        proportionalHours = (elapsed / totalWeeks) * TOTAL_REQUIRED_HOURS;
      }
    }

    // Hours per week average pace
    const hoursPerWeek = weeksElapsed > 0 ? avgEarned / weeksElapsed : 0;

    // Projected completion date
    let projectedDate: Date | null = null;
    let weeksRemaining: number | null = null;
    if (hoursPerWeek > 0 && avgEarned < TOTAL_REQUIRED_HOURS) {
      const hoursLeft = TOTAL_REQUIRED_HOURS - avgEarned;
      weeksRemaining = hoursLeft / hoursPerWeek;
      projectedDate = new Date(now.getTime() + weeksRemaining * 7 * 24 * 60 * 60 * 1000);
    } else if (avgEarned >= TOTAL_REQUIRED_HOURS) {
      projectedDate = now;
      weeksRemaining = 0;
    }

    // Weeks late vs expected end date
    let weeksLate: number | null = null;
    if (endDate && projectedDate && projectedDate > endDate) {
      weeksLate = (projectedDate.getTime() - endDate.getTime()) / (7 * 24 * 60 * 60 * 1000);
    }

    return {
      startDate,
      endDate,
      weeksElapsed,
      totalWeeks,
      proportionalHours,
      avgEarned,
      hoursPerWeek,
      projectedDate,
      weeksRemaining,
      weeksLate,
    };
  };

  // Determine pace status for an individual student
  const getStudentPace = (studentId: string): 'ahead' | 'on-track' | 'behind' | 'unknown' => {
    const cohortData = allCohorts.find(c => c.id === selectedCohort);
    const startDate = cohortData?.start_date ? new Date(cohortData.start_date) : null;
    const endDate = cohortData?.expected_end_date ? new Date(cohortData.expected_end_date) : null;

    if (!startDate || !endDate) return 'unknown';

    const now = new Date();
    const msPerWeek = 7 * 24 * 60 * 60 * 1000;
    const totalWeeks = Math.max(1, (endDate.getTime() - startDate.getTime()) / msPerWeek);
    const weeksElapsed = Math.max(0, (now.getTime() - startDate.getTime()) / msPerWeek);
    const elapsed = Math.min(weeksElapsed, totalWeeks);
    const proportionalHours = (elapsed / totalWeeks) * TOTAL_REQUIRED_HOURS;

    if (proportionalHours === 0) return 'unknown';

    const studentHours = getStudentHours(studentId);
    const earned = studentHours?.total_hours || 0;

    if (earned >= TOTAL_REQUIRED_HOURS) return 'ahead';
    const ratio = earned / proportionalHours;
    if (ratio > 1.05) return 'ahead';
    if (ratio < 0.80) return 'behind';
    return 'on-track';
  };

  const startEditing = (studentId: string, col: typeof DEPT_COLUMNS[number]) => {
    if (!userRole || !canEditClinical(userRole)) return;

    const existing = getStudentHours(studentId);
    setEditingCell(`${studentId}-${col.key}`);
    setEditValue({
      shifts: existing?.[col.shiftsField] || 0,
      hours: existing?.[col.hoursField] || 0,
    });
  };

  const saveHours = async (studentId: string, col: typeof DEPT_COLUMNS[number]) => {
    const cellKey = `${studentId}-${col.key}`;
    setSaving(cellKey);

    try {
      const updateData: Record<string, unknown> = {
        student_id: studentId,
        cohort_id: selectedCohort,
        [col.hoursField]: editValue.hours,
        [col.shiftsField]: editValue.shifts,
      };

      const res = await fetch('/api/clinical/hours', {
        method: 'POST',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(updateData),
      });

      if (res.ok) {
        await fetchCohortData();
        toast.success('Hours saved');
      } else {
        const errorData = await res.json();
        console.error('Error saving hours:', errorData);
        toast.error('Failed to save hours');
      }
    } catch (error) {
      console.error('Error saving hours:', error);
      toast.error('Failed to save hours');
    }
    setSaving(null);
    setEditingCell(null);
  };

  const cancelEditing = () => {
    setEditingCell(null);
    setEditValue({ shifts: 0, hours: 0 });
  };

  // Filter students
  const filteredStudents = students.filter(student => {
    if (!showInactive) {
      const s = student.status;
      if (s && s !== 'active' && s !== 'enrolled') return false;
    }
    if (searchQuery) {
      const search = searchQuery.toLowerCase();
      const name = `${student.first_name} ${student.last_name}`.toLowerCase();
      if (!name.includes(search)) return false;
    }
    return true;
  });

  // Category mapping for Platinum export columns
  interface CategoryMapping {
    name: string;
    patterns: string[];  // Patterns to match in header (case-insensitive)
    hoursField: keyof StudentHours;
    shiftsField: keyof StudentHours;
  }

  // IMPORTANT: Order matters! Check Peds ED/ICU BEFORE generic ED/ICU
  // so that "Pediatric Emergency Department" matches Peds ED, not ED
  const CATEGORY_MAPPINGS: CategoryMapping[] = [
    { name: 'Psych', patterns: ['behavioral', 'psychiatric', 'psych'], hoursField: 'psych_hours', shiftsField: 'psych_shifts' },
    // Peds categories MUST come before generic ED/ICU
    { name: 'Peds ED', patterns: ['pediatric emergency', 'peds ed', 'pediatric ed', 'ped ed'], hoursField: 'peds_ed_hours', shiftsField: 'peds_ed_shifts' },
    { name: 'Peds ICU', patterns: ['pediatric icu', 'peds icu', 'picu', 'ped icu'], hoursField: 'peds_icu_hours', shiftsField: 'peds_icu_shifts' },
    // Generic ED/ICU - these will only match if Peds patterns didn't match first
    { name: 'ED', patterns: ['emergency room', 'emergency dept', 'emergency department'], hoursField: 'ed_hours', shiftsField: 'ed_shifts' },
    { name: 'ICU', patterns: ['icu'], hoursField: 'icu_hours', shiftsField: 'icu_shifts' },
    { name: 'EMS Field', patterns: ['ems field', 'field experience', 'elective'], hoursField: 'ems_field_hours', shiftsField: 'ems_field_shifts' },
    { name: 'EMS Ridealong', patterns: ['ems ride', 'ride-along', 'ridealong', 'ride along'], hoursField: 'ems_ridealong_hours', shiftsField: 'ems_ridealong_shifts' },
    { name: 'OB', patterns: ['ob', 'labor', 'l&d', 'obstetric'], hoursField: 'ob_hours', shiftsField: 'ob_shifts' },
    { name: 'OR', patterns: ['or inpatient', 'or ', 'operating room', 'inpatient'], hoursField: 'or_hours', shiftsField: 'or_shifts' },
    { name: 'Cardiology', patterns: ['cardiology', 'cardiac', 'ccl', 'cath lab'], hoursField: 'cardiology_hours', shiftsField: 'cardiology_shifts' },
  ];

  // Categories to ignore
  const IGNORE_PATTERNS = ['other', 'simulation', 'grand total', 'total'];

  interface DetectedCategory {
    name: string;
    mapping: CategoryMapping | null;
    hoursCol: number | null;
    shiftsCol: number | null;
    pendingCol: number | null;
  }

  // Platinum Import Functions - REPLACES values (not increments)
  const handleFileSelect = async (event: React.ChangeEvent<HTMLInputElement>) => {
    const file = event.target.files?.[0];
    if (!file) return;

    setImportError(null);

    try {
      const XLSX = await import('xlsx');
      const data = await file.arrayBuffer();
      const workbook = XLSX.read(data);
      const sheetName = workbook.SheetNames[0];
      const worksheet = workbook.Sheets[sheetName];
      const jsonData = XLSX.utils.sheet_to_json(worksheet, { header: 1 }) as unknown[][];

      // Dynamic column detection with STRICT BOUNDARIES
      // Platinum export structure (1-indexed in Excel):
      // Row 1: Filter headers
      // Row 2: Column area headers
      // Row 3: Row area headers
      // Row 4 (index 3): Category headers (merged cells - only first col has value)
      // Row 5 (index 4): Sub-headers (Hours, Pending Hours, Shifts)
      // Row 6+ (index 5+): Data rows

      const categoryRow = jsonData[3] || [];
      const subHeaderRow = jsonData[4] || [];

      // PASS 1: Find all category start columns
      interface CategoryStart {
        name: string;
        nameLower: string;
        startCol: number;
        endCol: number;  // Will be set in pass 2
      }

      const categoryStarts: CategoryStart[] = [];
      for (let col = 1; col < categoryRow.length; col++) {
        const cellValue = String(categoryRow[col] || '').trim();
        if (cellValue && cellValue.length > 0) {
          categoryStarts.push({
            name: cellValue,
            nameLower: cellValue.toLowerCase(),
            startCol: col,
            endCol: 0  // Will be set in pass 2
          });
        }
      }

      // PASS 2: Assign end columns (where next category starts, or end of row)
      const maxCol = Math.max(categoryRow.length, subHeaderRow.length);
      for (let i = 0; i < categoryStarts.length; i++) {
        const nextStart = categoryStarts[i + 1]?.startCol || maxCol;
        categoryStarts[i].endCol = nextStart;
      }

      // PASS 3: Find Hours/Shifts ONLY within each category's column boundaries
      const detectedCategories: DetectedCategory[] = [];

      for (const cat of categoryStarts) {
        // Check if should be ignored
        const shouldIgnore = IGNORE_PATTERNS.some(p => cat.nameLower.includes(p));

        // Find matching category mapping
        let mapping: CategoryMapping | null = null;
        if (!shouldIgnore) {
          // Special handling: Peds categories must NOT match generic ED/ICU
          const isPeds = cat.nameLower.includes('pediatric') || cat.nameLower.includes('peds') || cat.nameLower.includes('picu');

          for (const m of CATEGORY_MAPPINGS) {
            // Skip generic ED/ICU if this is a Peds category - let it match Peds ED/ICU instead
            if ((m.name === 'ICU' || m.name === 'ED') && isPeds) continue;

            if (m.patterns.some(p => cat.nameLower.includes(p))) {
              mapping = m;
              break;
            }
          }
        }

        // Find Hours/Shifts columns ONLY within [startCol, endCol)
        let hoursCol: number | null = null;
        let shiftsCol: number | null = null;
        let pendingCol: number | null = null;

        for (let col = cat.startCol; col < cat.endCol; col++) {
          const header = String(subHeaderRow[col] || '').trim().toLowerCase();

          if (!header) continue;

          // IMPORTANT: Check "Pending Hours" FIRST (before plain "Hours")
          // because "pending hours" contains "hours"
          if (header.includes('pending') && pendingCol === null) {
            pendingCol = col;
          }
          // Check for "Hours" (exact match or starts with "hour")
          else if ((header === 'hours' || header === 'hour') && hoursCol === null) {
            hoursCol = col;
          }
          // Check for "Shifts"
          else if ((header === 'shifts' || header === 'shift') && shiftsCol === null) {
            shiftsCol = col;
          }
        }

        detectedCategories.push({
          name: cat.nameLower,
          mapping,
          hoursCol,
          shiftsCol,
          pendingCol
        });
      }


      // Data starts at row 6 (index 5)
      const dataRows = jsonData.slice(5);

      // Filter out empty rows and the grand total row
      const validRows = dataRows.filter((row: unknown[]) => {
        const name = row[0];
        if (!name || typeof name !== 'string') return false;
        if (name.toLowerCase().includes('grand total')) return false;
        return true;
      });

      // Parse helper
      const parseNum = (val: unknown): number => {
        if (typeof val === 'number') return val;
        if (typeof val === 'string') return parseFloat(val) || 0;
        return 0;
      };

      // Parse and match students using detected columns
      const preview: ImportPreviewRow[] = validRows.map((row: unknown[]) => {
        const rawName = String(row[0] || '').trim();

        // Detect inactive students: Platinum marks them with a leading asterisk (*)
        const isInactive = rawName.startsWith('*');
        const name = isInactive ? rawName.replace(/^\*+/, '').trim() : rawName;

        // Build row data dynamically from detected categories
        const rowData: Record<string, number> = {};

        for (const cat of detectedCategories) {
          if (cat.mapping && cat.hoursCol !== null) {
            rowData[cat.mapping.hoursField] = parseNum(row[cat.hoursCol]);
          }
          if (cat.mapping && cat.shiftsCol !== null) {
            rowData[cat.mapping.shiftsField] = parseNum(row[cat.shiftsCol]);
          }
        }

        // Match using the stripped name (without asterisk)
        const matchedStudent = matchStudentByName(name);
        // Find similar names if no match
        const similarNames = matchedStudent ? [] : findSimilarNames(name);

        return {
          name: rawName,
          matchedStudent,
          similarNames,
          data: rowData as Partial<StudentHours>,
          isInactive,
        };
      });

      // Show warning if some categories weren't mapped
      const unmappedCategories = detectedCategories
        .filter(c => !c.mapping && !IGNORE_PATTERNS.some(p => c.name.includes(p)))
        .map(c => c.name);

      if (unmappedCategories.length > 0) {
        console.warn('Unmapped categories found:', unmappedCategories);
      }

      setImportPreview(preview);
      setShowImportModal(true);
    } catch (error) {
      console.error('Error parsing file:', error);
      setImportError('Failed to parse file. Please ensure it is a valid Excel file.');
    }

    if (fileInputRef.current) {
      fileInputRef.current.value = '';
    }
  };

  // Normalize name for comparison
  const normalizeName = (name: string): string => {
    return name
      .toLowerCase()
      .trim()
      .replace(/\s+/g, ' ')  // Multiple spaces to single
      .replace(/[.,]/g, '')   // Remove periods and commas
      .trim();
  };

  // Calculate Levenshtein distance for fuzzy matching
  const levenshteinDistance = (a: string, b: string): number => {
    if (a.length === 0) return b.length;
    if (b.length === 0) return a.length;

    const matrix = Array(b.length + 1).fill(null).map(() => Array(a.length + 1).fill(null));

    for (let i = 0; i <= a.length; i++) matrix[0][i] = i;
    for (let j = 0; j <= b.length; j++) matrix[j][0] = j;

    for (let j = 1; j <= b.length; j++) {
      for (let i = 1; i <= a.length; i++) {
        const cost = a[i - 1] === b[j - 1] ? 0 : 1;
        matrix[j][i] = Math.min(
          matrix[j][i - 1] + 1,
          matrix[j - 1][i] + 1,
          matrix[j - 1][i - 1] + cost
        );
      }
    }
    return matrix[b.length][a.length];
  };

  // Get student name variations for matching
  const getNameVariations = (student: Student): string[] => {
    const first = normalizeName(student.first_name);
    const last = normalizeName(student.last_name);
    return [
      `${first} ${last}`,           // John Smith
      `${last} ${first}`,           // Smith John
      `${last}, ${first}`,          // Smith, John
      `${last} ${first[0]}`,        // Smith J
      `${first[0]} ${last}`,        // J Smith
    ];
  };

  // Find similar names for suggestions
  const findSimilarNames = (importName: string, maxSuggestions: number = 3): string[] => {
    const normalized = normalizeName(importName);

    const scored = students.map(s => {
      const fullName = `${s.first_name} ${s.last_name}`;
      const variations = getNameVariations(s);

      // Find minimum distance across all variations
      const minDistance = Math.min(
        ...variations.map(v => levenshteinDistance(normalized, v))
      );

      return { student: s, name: fullName, distance: minDistance };
    });

    // Sort by distance and return top suggestions
    return scored
      .filter(s => s.distance <= 5)  // Only reasonably close matches
      .sort((a, b) => a.distance - b.distance)
      .slice(0, maxSuggestions)
      .map(s => s.name);
  };

  const matchStudentByName = (importName: string): Student | null => {
    const normalized = normalizeName(importName);

    // Exact match attempts
    let match = students.find(s => {
      const variations = getNameVariations(s);
      return variations.some(v => v === normalized);
    });

    if (match) return match;

    // Partial match: last name + first initial
    match = students.find(s => {
      const lastName = normalizeName(s.last_name);
      const firstInitial = s.first_name[0]?.toLowerCase();
      return normalized.includes(lastName) &&
             normalized.includes(firstInitial);
    });

    if (match) return match;

    // Fuzzy match: very close Levenshtein distance (≤2)
    const fuzzyMatch = students.find(s => {
      const variations = getNameVariations(s);
      return variations.some(v => levenshteinDistance(normalized, v) <= 2);
    });

    return fuzzyMatch || null;
  };

  // Handle manual match selection
  const handleManualMatch = (rowIndex: number, studentId: string) => {
    const student = students.find(s => s.id === studentId) || null;
    setImportPreview(prev => {
      const updated = [...prev];
      updated[rowIndex] = {
        ...updated[rowIndex],
        matchedStudent: student,
        manualMatch: studentId,
        similarNames: [], // Clear suggestions once matched
      };
      return updated;
    });
  };

  // Import REPLACES/SETS values (Platinum shows cumulative totals, not increments)
  const executeImport = async () => {
    setImporting(true);
    setImportError(null);

    const matchedRows = importPreview.filter(row => row.matchedStudent);
    const results = { success: 0, failed: 0, markedInactive: 0, failedNames: [] as string[] };

    for (const row of matchedRows) {
      if (!row.matchedStudent) continue;

      try {
        if (row.isInactive) {
          // Mark the student as inactive - don't import their hours
          const res = await fetch(`/api/lab-management/students/${row.matchedStudent.id}`, {
            method: 'PATCH',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify({ status: 'inactive' }),
          });
          if (res.ok) {
            results.markedInactive++;
          } else {
            results.failed++;
            results.failedNames.push(row.name);
          }
        } else {
          // POST with the values - API will SET (not increment) these values
          const updateData = {
            student_id: row.matchedStudent.id,
            cohort_id: selectedCohort,
            ...row.data,
          };

          const res = await fetch('/api/clinical/hours', {
            method: 'POST',
            headers: { 'Content-Type': 'application/json' },
            body: JSON.stringify(updateData),
          });

          if (res.ok) {
            results.success++;
          } else {
            results.failed++;
            results.failedNames.push(row.name);
          }
        }
      } catch (error) {
        console.error(`Import error for ${row.name}:`, error);
        results.failed++;
        results.failedNames.push(row.name);
      }
    }

    // Check unmatched count
    const unmatchedNames = importPreview
      .filter(row => !row.matchedStudent)
      .map(row => row.name);

    await fetchCohortData();

    // Show summary message
    const activeImported = results.success;
    const inactiveMarked = results.markedInactive;
    if (results.failed > 0 || unmatchedNames.length > 0) {
      let message = `Imported ${activeImported} student${activeImported !== 1 ? 's' : ''}.`;
      if (inactiveMarked > 0) {
        message += ` ${inactiveMarked} marked inactive.`;
      }
      if (results.failed > 0) {
        message += ` ${results.failed} failed: ${results.failedNames.join(', ')}.`;
      }
      if (unmatchedNames.length > 0) {
        message += ` ${unmatchedNames.length} skipped (no match): ${unmatchedNames.slice(0, 3).join(', ')}${unmatchedNames.length > 3 ? '...' : ''}.`;
      }
      setImportError(message);
      // Don't close modal if there were issues, let user see summary
      if (results.failed === 0) {
        setShowImportModal(false);
        setImportPreview([]);
        const parts = [];
        if (activeImported > 0) parts.push(`${activeImported} student${activeImported !== 1 ? 's' : ''} imported`);
        if (inactiveMarked > 0) parts.push(`${inactiveMarked} marked inactive`);
        toast.success(parts.join(', '));
      } else {
        toast.error(`Import completed with errors: ${results.failed} failed`);
      }
    } else {
      setShowImportModal(false);
      setImportPreview([]);
      const parts = [];
      if (activeImported > 0) parts.push(`${activeImported} student${activeImported !== 1 ? 's' : ''} imported`);
      if (inactiveMarked > 0) parts.push(`${inactiveMarked} marked inactive`);
      toast.success(parts.join(', ') || 'Import complete');
    }

    setImporting(false);
  };

  if (status === 'loading' || loading) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-teal-50 to-cyan-100 dark:from-gray-900 dark:to-gray-800">
        <div className="animate-spin rounded-full h-12 w-12 border-b-2 border-teal-600"></div>
      </div>
    );
  }

  if (!session) return null;

  if (fetchError) {
    return (
      <div className="min-h-screen flex items-center justify-center bg-gradient-to-br from-teal-50 to-cyan-100 dark:from-gray-900 dark:to-gray-800">
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow-lg p-8 max-w-md text-center">
          <AlertTriangle className="w-12 h-12 text-amber-500 mx-auto mb-4" />
          <h2 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">Failed to Load</h2>
          <p className="text-gray-600 dark:text-gray-400 mb-4">{fetchError}</p>
          <button
            onClick={() => fetchInitialData()}
            className="px-4 py-2 bg-teal-600 text-white rounded-lg hover:bg-teal-700 transition-colors"
          >
            Try Again
          </button>
        </div>
      </div>
    );
  }

  const canEdit = userRole && canEditClinical(userRole);
  const unmatchedCount = importPreview.filter(r => !r.matchedStudent).length;
  const matchedCount = importPreview.filter(r => r.matchedStudent).length;
  const cohortStats = getCohortStats();
  const paceInfo = getPaceInfo();
  const deptAvg = getDeptAvgHours();

  // Check if selected cohort is Paramedic program
  const selectedCohortData = cohorts.find(c => c.id === selectedCohort);
  const isParamedicCohort = isParamedicAbbrev(selectedCohortData?.program?.abbreviation);

  // Format a projected date nicely
  const formatProjectedDate = (date: Date | null): string => {
    if (!date) return 'Unknown';
    return date.toLocaleDateString('en-US', { month: 'short', day: 'numeric', year: 'numeric' });
  };

  return (
    <div className="min-h-screen bg-gradient-to-br from-teal-50 to-cyan-100 dark:from-gray-900 dark:to-gray-800">
      {/* Header */}
      <div className="bg-white dark:bg-gray-800 shadow-sm print:hidden">
        <div className="max-w-full mx-auto px-4 py-6">
          <Breadcrumbs className="mb-2" />
          <div className="flex items-center justify-between">
            <div className="flex items-center gap-3">
              <div className="p-2 bg-blue-100 dark:bg-blue-900/30 rounded-lg">
                <Clock className="w-6 h-6 text-blue-600 dark:text-blue-400" />
              </div>
              <div>
                <h1 className="text-2xl font-bold text-gray-900 dark:text-white">Clinical Hours Tracker</h1>
                <p className="text-gray-600 dark:text-gray-400">Track shifts and hours by department</p>
              </div>
            </div>
            <div className="flex items-center gap-3">
              {/* View Toggle */}
              <div className="flex items-center bg-gray-100 dark:bg-gray-700 rounded-lg p-1">
                <button
                  onClick={() => setViewMode('dashboard')}
                  className={`flex items-center gap-1 px-3 py-1.5 rounded text-sm transition-colors ${
                    viewMode === 'dashboard'
                      ? 'bg-white dark:bg-gray-600 shadow text-blue-600 dark:text-blue-400'
                      : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'
                  }`}
                >
                  <LayoutGrid className="w-4 h-4" />
                  Dashboard
                </button>
                <button
                  onClick={() => setViewMode('detailed')}
                  className={`flex items-center gap-1 px-3 py-1.5 rounded text-sm transition-colors ${
                    viewMode === 'detailed'
                      ? 'bg-white dark:bg-gray-600 shadow text-blue-600 dark:text-blue-400'
                      : 'text-gray-600 dark:text-gray-400 hover:text-gray-900 dark:hover:text-white'
                  }`}
                >
                  <Table2 className="w-4 h-4" />
                  Detailed
                </button>
              </div>

              <button
                onClick={() => window.print()}
                className="flex items-center gap-2 px-3 py-2 text-sm text-gray-600 dark:text-gray-400 hover:bg-gray-100 dark:hover:bg-gray-800 rounded-lg"
                aria-label="Print this page"
              >
                <Printer className="w-4 h-4" />
                Print
              </button>

              {canEdit && selectedCohort && (
                <>
                  <input
                    ref={fileInputRef}
                    type="file"
                    accept=".xlsx,.xls"
                    onChange={handleFileSelect}
                    className="hidden"
                  />
                  <button
                    onClick={() => fileInputRef.current?.click()}
                    className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 transition-colors"
                  >
                    <Upload className="w-4 h-4" />
                    Import from Platinum
                  </button>
                </>
              )}
            </div>
          </div>
        </div>
      </div>

      <main className="max-w-full mx-auto px-4 py-6 space-y-4">
        <PageErrorBoundary>
        {/* Filters */}
        <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4 print:hidden">
          <div className="flex flex-wrap gap-4 items-center">
            <div className="flex items-center gap-2">
              <Filter className="w-5 h-5 text-gray-400" aria-hidden="true" />
              <label htmlFor="clinical-program-select" className="sr-only">Filter by Program</label>
              <select
                id="clinical-program-select"
                value={selectedProgram}
                onChange={(e) => setSelectedProgram(e.target.value)}
                className="px-3 py-2 border rounded-lg text-gray-900 dark:text-white bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600"
              >
                <option value="Paramedic">Paramedic</option>
                <option value="AEMT">AEMT</option>
                <option value="EMT">EMT</option>
                <option value="All">All Programs</option>
              </select>
            </div>

            <div className="flex items-center gap-2">
              <Users className="w-5 h-5 text-gray-400" aria-hidden="true" />
              <label htmlFor="clinical-cohort-select" className="sr-only">Select Cohort</label>
              <select
                id="clinical-cohort-select"
                value={selectedCohort}
                onChange={(e) => setSelectedCohort(e.target.value)}
                className="px-3 py-2 border rounded-lg text-gray-900 dark:text-white bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 min-w-[200px]"
              >
                <option value="">Select Cohort</option>
                {cohorts.map(c => (
                  <option key={c.id} value={c.id}>
                    {c.program?.abbreviation || 'PMD'} Group {c.cohort_number}
                  </option>
                ))}
              </select>
            </div>

            <div className="flex-1 min-w-[200px] relative">
              <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 w-4 h-4 text-gray-400" aria-hidden="true" />
              <label htmlFor="clinical-student-search" className="sr-only">Search student</label>
              <input
                id="clinical-student-search"
                type="text"
                value={searchQuery}
                onChange={(e) => setSearchQuery(e.target.value)}
                placeholder="Search student..."
                className="w-full pl-10 pr-4 py-2 border rounded-lg text-gray-900 dark:text-white bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600"
              />
            </div>

            <label className="flex items-center gap-2 cursor-pointer select-none">
              <input
                type="checkbox"
                checked={showInactive}
                onChange={(e) => setShowInactive(e.target.checked)}
                className="rounded border-gray-300 dark:border-gray-600 text-teal-600"
              />
              <span className="text-sm text-gray-600 dark:text-gray-400">Show inactive students</span>
            </label>

            {viewMode === 'detailed' && (
              <div className="text-sm text-gray-500 dark:text-gray-400">
                Click any cell to edit shifts/hours
              </div>
            )}
          </div>
        </div>

        {/* Non-Paramedic Cohort Message */}
        {selectedCohort && !isParamedicCohort && (
          <div className="bg-blue-50 dark:bg-blue-900/20 rounded-lg shadow p-8 text-center">
            <AlertTriangle className="w-12 h-12 text-blue-500 mx-auto mb-3" />
            <h3 className="text-lg font-semibold text-gray-900 dark:text-white mb-2">
              Clinical Hours Tracking Not Applicable
            </h3>
            <p className="text-gray-600 dark:text-gray-400">
              Clinical hours tracking is only applicable to the Paramedic program.
            </p>
            <p className="text-sm text-gray-500 dark:text-gray-500 mt-2">
              Selected cohort: {selectedCohortData?.program?.abbreviation || 'Unknown'} Group {selectedCohortData?.cohort_number}
            </p>
          </div>
        )}

        {/* Cohort Summary Stats */}
        {selectedCohort && isParamedicCohort && students.length > 0 && (
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-4">
            <div className="flex items-center justify-between flex-wrap gap-4">
              <div className="flex items-center gap-6 flex-wrap">
                <div className="flex items-center gap-2">
                  <TrendingUp className="w-5 h-5 text-blue-500" />
                  <span className="text-sm text-gray-600 dark:text-gray-400">
                    <span className="font-semibold text-gray-900 dark:text-white">{cohortStats.completedCount}</span> of {cohortStats.totalStudents} students completed all hours
                  </span>
                </div>
                <div className="h-4 w-px bg-gray-300 dark:bg-gray-600 hidden sm:block" />
                <div className="flex items-center gap-2">
                  <span className="text-sm text-gray-600 dark:text-gray-400">
                    Cohort average: <span className="font-semibold text-gray-900 dark:text-white">{cohortStats.averagePercentage}%</span> complete
                  </span>
                </div>
                {/* Projected completion */}
                {paceInfo.hoursPerWeek > 0 && (
                  <>
                    <div className="h-4 w-px bg-gray-300 dark:bg-gray-600 hidden sm:block" />
                    <div className="flex items-center gap-2">
                      <span className="text-sm text-gray-600 dark:text-gray-400">
                        {paceInfo.weeksLate !== null && paceInfo.weeksLate > 0 ? (
                          <span className="text-orange-600 dark:text-orange-400">
                            At current pace: <span className="font-semibold">{formatProjectedDate(paceInfo.projectedDate)}</span>
                            <span className="ml-1 text-xs">({Math.round(paceInfo.weeksLate)}w late)</span>
                          </span>
                        ) : paceInfo.avgEarned >= TOTAL_REQUIRED_HOURS ? (
                          <span className="text-green-600 dark:text-green-400 font-semibold">Cohort has completed required hours</span>
                        ) : (
                          <span>
                            On track to complete by{' '}
                            <span className="font-semibold text-gray-900 dark:text-white">{formatProjectedDate(paceInfo.projectedDate)}</span>
                          </span>
                        )}
                      </span>
                    </div>
                  </>
                )}
              </div>
              <div className="flex items-center gap-3 text-xs">
                <span className="flex items-center gap-1">
                  <span className="w-3 h-3 rounded bg-green-500"></span> Complete
                </span>
                <span className="flex items-center gap-1">
                  <span className="w-3 h-3 rounded bg-yellow-500"></span> 50%+
                </span>
                <span className="flex items-center gap-1">
                  <span className="w-3 h-3 rounded bg-red-500"></span> &lt;50%
                </span>
              </div>
            </div>
          </div>
        )}

        {/* Progress Visualization: Overall ring + department bars */}
        {selectedCohort && isParamedicCohort && students.length > 0 && (
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-5">
            <h3 className="text-sm font-semibold text-gray-700 dark:text-gray-300 mb-4 uppercase tracking-wide">Cohort Progress</h3>
            <div className="flex flex-col lg:flex-row gap-6">
              {/* Overall ring */}
              <div className="flex flex-col items-center justify-center min-w-[140px]">
                <div className="relative w-28 h-28">
                  <svg viewBox="0 0 36 36" className="w-28 h-28 -rotate-90">
                    <circle
                      cx="18" cy="18" r="15.9"
                      fill="none"
                      stroke="currentColor"
                      className="text-gray-200 dark:text-gray-700"
                      strokeWidth="3"
                    />
                    <circle
                      cx="18" cy="18" r="15.9"
                      fill="none"
                      stroke="currentColor"
                      className={cohortStats.averagePercentage >= 100 ? 'text-green-500' : cohortStats.averagePercentage >= 50 ? 'text-yellow-500' : 'text-red-500'}
                      strokeWidth="3"
                      strokeDasharray={`${cohortStats.averagePercentage} ${100 - cohortStats.averagePercentage}`}
                      strokeDashoffset="0"
                      strokeLinecap="round"
                    />
                  </svg>
                  <div className="absolute inset-0 flex flex-col items-center justify-center">
                    <span className={`text-xl font-bold ${cohortStats.averagePercentage >= 100 ? 'text-green-600' : cohortStats.averagePercentage >= 50 ? 'text-yellow-600' : 'text-red-600'}`}>
                      {cohortStats.averagePercentage}%
                    </span>
                  </div>
                </div>
                <p className="text-xs text-gray-500 dark:text-gray-400 mt-2 text-center">
                  Overall<br />
                  <span className="font-medium text-gray-700 dark:text-gray-300">{Math.round(paceInfo.avgEarned)}/{TOTAL_REQUIRED_HOURS}h avg</span>
                </p>
              </div>

              {/* Department progress bars */}
              <div className="flex-1 grid grid-cols-1 sm:grid-cols-2 xl:grid-cols-4 gap-3">
                {DEPT_PROGRESS_ITEMS.map(dept => {
                  const avg = deptAvg[dept.key] || 0;
                  const pct = Math.min(Math.round((avg / dept.required) * 100), 100);
                  return (
                    <div key={dept.key} className="flex flex-col gap-1">
                      <div className="flex items-center justify-between text-xs">
                        <span className="font-medium text-gray-700 dark:text-gray-300">{dept.label}</span>
                        <span className="text-gray-500 dark:text-gray-400">
                          {avg.toFixed(1)}/{dept.required}h
                        </span>
                      </div>
                      <div className="h-2 bg-gray-200 dark:bg-gray-700 rounded-full overflow-hidden">
                        <div
                          className={`h-full ${dept.color} transition-all`}
                          style={{ width: `${pct}%` }}
                        />
                      </div>
                      <div className="text-xs text-right">
                        <span className={`font-medium ${pct >= 100 ? 'text-green-600 dark:text-green-400' : pct >= 50 ? 'text-yellow-600 dark:text-yellow-400' : 'text-red-600 dark:text-red-400'}`}>
                          {pct}%
                        </span>
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>
        )}

        {/* Dashboard View */}
        {selectedCohort && isParamedicCohort && viewMode === 'dashboard' && (
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 dark:bg-gray-700">
                  <tr>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider sticky left-0 bg-gray-50 dark:bg-gray-700 z-10">
                      Student
                    </th>
                    {DEPT_COLUMNS.map(col => (
                      <th
                        key={col.key}
                        className="px-2 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider whitespace-nowrap"
                        title={col.fullName}
                      >
                        <div>{col.label}</div>
                        {col.required > 0 && (
                          <div className="text-[10px] font-normal text-gray-400">/{col.required}h</div>
                        )}
                      </th>
                    ))}
                    <th className="px-3 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider bg-blue-50 dark:bg-blue-900/20">
                      Total<br/><span className="text-[10px] font-normal">/{TOTAL_REQUIRED_HOURS}h</span>
                    </th>
                    <th className="px-4 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider w-32">
                      Progress
                    </th>
                    <th className="px-3 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider w-24">
                      Pace
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                  {filteredStudents.length === 0 ? (
                    <tr>
                      <td colSpan={DEPT_COLUMNS.length + 4} className="px-4 py-12 text-center">
                        <div className="flex flex-col items-center gap-2 text-gray-500 dark:text-gray-400">
                          <Users className="w-12 h-12 text-gray-300 dark:text-gray-600" />
                          <p className="font-medium">No students found</p>
                          <p className="text-sm">Try adjusting your search or select a different cohort</p>
                        </div>
                      </td>
                    </tr>
                  ) : (
                    filteredStudents.map(student => {
                      const studentHours = getStudentHours(student.id);
                      const totalHours = studentHours?.total_hours || 0;
                      const progressPercent = Math.min(Math.round((totalHours / TOTAL_REQUIRED_HOURS) * 100), 100);
                      const pace = getStudentPace(student.id);

                      return (
                        <tr key={student.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/50">
                          <td className="px-4 py-2 whitespace-nowrap sticky left-0 bg-white dark:bg-gray-800 z-10">
                            <div className="font-medium text-gray-900 dark:text-white text-sm">
                              {student.last_name}, {student.first_name}
                            </div>
                          </td>
                          {DEPT_COLUMNS.map(col => {
                            const hours = studentHours?.[col.hoursField] || 0;
                            const colorClass = getCompletionColor(hours, col.required);

                            return (
                              <td key={col.key} className="px-2 py-2 text-center">
                                <div className={`inline-block px-2 py-1 rounded text-xs font-medium ${colorClass}`}>
                                  {hours}{col.required > 0 ? `/${col.required}` : ''}
                                </div>
                              </td>
                            );
                          })}
                          <td className="px-3 py-2 text-center bg-blue-50 dark:bg-blue-900/20">
                            <div className="font-semibold text-blue-700 dark:text-blue-300 text-sm">
                              {totalHours}/{TOTAL_REQUIRED_HOURS}
                            </div>
                          </td>
                          <td className="px-4 py-2">
                            <div className="flex items-center gap-2">
                              <div className="flex-1 h-2 bg-gray-200 dark:bg-gray-600 rounded-full overflow-hidden">
                                <div
                                  className={`h-full ${getProgressColor(progressPercent)} transition-all`}
                                  style={{ width: `${progressPercent}%` }}
                                />
                              </div>
                              <span className={`text-xs font-medium min-w-[3rem] text-right ${
                                progressPercent >= 100 ? 'text-green-600' :
                                progressPercent >= 50 ? 'text-yellow-600' : 'text-red-600'
                              }`}>
                                {progressPercent}%
                              </span>
                            </div>
                          </td>
                          <td className="px-3 py-2 text-center">
                            {pace === 'unknown' ? (
                              <span className="text-xs text-gray-400 dark:text-gray-500">N/A</span>
                            ) : pace === 'ahead' ? (
                              <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-green-100 dark:bg-green-900/30 text-green-700 dark:text-green-300">
                                Ahead
                              </span>
                            ) : pace === 'behind' ? (
                              <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-red-100 dark:bg-red-900/30 text-red-700 dark:text-red-300">
                                Behind
                              </span>
                            ) : (
                              <span className="inline-flex items-center px-2 py-0.5 rounded-full text-xs font-medium bg-yellow-100 dark:bg-yellow-900/30 text-yellow-700 dark:text-yellow-300">
                                On Track
                              </span>
                            )}
                          </td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {/* Detailed View (original editable grid) */}
        {selectedCohort && isParamedicCohort && viewMode === 'detailed' && (
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow overflow-hidden">
            <div className="overflow-x-auto">
              <table className="w-full">
                <thead className="bg-gray-50 dark:bg-gray-700">
                  <tr>
                    <th className="px-4 py-3 text-left text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider sticky left-0 bg-gray-50 dark:bg-gray-700 z-10">
                      Student
                    </th>
                    {DEPT_COLUMNS.map(col => (
                      <th
                        key={col.key}
                        className="px-3 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider whitespace-nowrap"
                        title={col.fullName}
                      >
                        <div>{col.label}</div>
                        <div className="text-[10px] font-normal normal-case text-gray-400">{col.fullName}</div>
                      </th>
                    ))}
                    <th className="px-4 py-3 text-center text-xs font-medium text-gray-500 dark:text-gray-400 uppercase tracking-wider bg-blue-50 dark:bg-blue-900/20">
                      Total
                    </th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                  {filteredStudents.length === 0 ? (
                    <tr>
                      <td colSpan={DEPT_COLUMNS.length + 2} className="px-4 py-12 text-center">
                        <div className="flex flex-col items-center gap-2 text-gray-500 dark:text-gray-400">
                          <Users className="w-12 h-12 text-gray-300 dark:text-gray-600" />
                          <p className="font-medium">No students found</p>
                          <p className="text-sm">Try adjusting your search or select a different cohort</p>
                        </div>
                      </td>
                    </tr>
                  ) : (
                    filteredStudents.map(student => {
                      const studentHours = getStudentHours(student.id);

                      return (
                        <tr key={student.id} className="hover:bg-gray-50 dark:hover:bg-gray-700/50">
                          <td className="px-4 py-3 whitespace-nowrap sticky left-0 bg-white dark:bg-gray-800 z-10">
                            <div className="font-medium text-gray-900 dark:text-white">
                              {student.first_name} {student.last_name}
                            </div>
                          </td>
                          {DEPT_COLUMNS.map(col => {
                            const hours = studentHours?.[col.hoursField] || 0;
                            const shifts = studentHours?.[col.shiftsField] || 0;
                            const cellKey = `${student.id}-${col.key}`;
                            const isEditing = editingCell === cellKey;
                            const isSaving = saving === cellKey;

                            return (
                              <td key={col.key} className="px-3 py-2 text-center">
                                {isEditing ? (
                                  <div className="flex flex-col gap-1 min-w-[80px]">
                                    <label htmlFor={`shifts-${cellKey}`} className="text-[10px] text-gray-400 text-left">Shifts:</label>
                                    <input
                                      id={`shifts-${cellKey}`}
                                      type="number"
                                      value={editValue.shifts}
                                      onChange={(e) => setEditValue({ ...editValue, shifts: parseInt(e.target.value) || 0 })}
                                      className="w-full px-2 py-1 text-xs border rounded bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white"
                                      min="0"
                                    />
                                    <label htmlFor={`hours-${cellKey}`} className="text-[10px] text-gray-400 text-left">Hours:</label>
                                    <input
                                      id={`hours-${cellKey}`}
                                      type="number"
                                      value={editValue.hours}
                                      onChange={(e) => setEditValue({ ...editValue, hours: parseFloat(e.target.value) || 0 })}
                                      className="w-full px-2 py-1 text-xs border rounded bg-white dark:bg-gray-700 border-gray-300 dark:border-gray-600 text-gray-900 dark:text-white"
                                      min="0"
                                      step="0.5"
                                    />
                                    <div className="flex gap-1">
                                      <button
                                        onClick={() => saveHours(student.id, col)}
                                        disabled={isSaving}
                                        className="flex-1 px-2 py-1 bg-blue-600 text-white text-xs rounded hover:bg-blue-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
                                        title="Save hours"
                                      >
                                        {isSaving ? <Loader2 className="w-3 h-3 animate-spin mx-auto" /> : <Save className="w-3 h-3 mx-auto" />}
                                      </button>
                                      <button
                                        onClick={cancelEditing}
                                        className="flex-1 px-2 py-1 bg-gray-300 dark:bg-gray-600 text-gray-700 dark:text-gray-200 text-xs rounded hover:bg-gray-400 dark:hover:bg-gray-500"
                                      >
                                        X
                                      </button>
                                    </div>
                                  </div>
                                ) : (
                                  <button
                                    onClick={() => startEditing(student.id, col)}
                                    disabled={!canEdit}
                                    className={`min-w-[60px] px-2 py-1 rounded text-xs transition-colors ${
                                      shifts > 0 || hours > 0
                                        ? 'bg-blue-100 dark:bg-blue-900/30 text-blue-700 dark:text-blue-300'
                                        : 'bg-gray-100 dark:bg-gray-700 text-gray-400'
                                    } ${canEdit ? 'hover:bg-blue-200 dark:hover:bg-blue-900/50 cursor-pointer' : 'cursor-not-allowed'}`}
                                  >
                                    {shifts > 0 || hours > 0 ? (
                                      <div>
                                        <div className="font-medium">{shifts}s</div>
                                        <div className="text-[10px]">{hours}h</div>
                                      </div>
                                    ) : (
                                      '-'
                                    )}
                                  </button>
                                )}
                              </td>
                            );
                          })}
                          <td className="px-4 py-3 text-center bg-blue-50 dark:bg-blue-900/20">
                            <div className="font-semibold text-blue-700 dark:text-blue-300">
                              {studentHours?.total_shifts || 0}s / {studentHours?.total_hours || 0}h
                            </div>
                          </td>
                        </tr>
                      );
                    })
                  )}
                </tbody>
              </table>
            </div>
          </div>
        )}

        {!selectedCohort && (
          <div className="bg-white dark:bg-gray-800 rounded-lg shadow p-8 text-center">
            <Users className="w-12 h-12 text-gray-300 dark:text-gray-600 mx-auto mb-3" />
            <p className="text-gray-500 dark:text-gray-400">Select a cohort to view clinical hours</p>
          </div>
        )}
        </PageErrorBoundary>
      </main>

      {/* Import Preview Modal */}
      {showImportModal && (
        <div
          className="fixed inset-0 bg-black bg-opacity-50 flex items-center justify-center z-50 p-4"
          role="dialog"
          aria-modal="true"
          aria-labelledby="import-modal-title"
        >
          <div className="bg-white dark:bg-gray-800 rounded-xl shadow-xl max-w-4xl w-full max-h-[90vh] overflow-hidden">
            <div className="px-6 py-4 border-b border-gray-200 dark:border-gray-700 flex items-center justify-between">
              <div className="flex items-center gap-3">
                <FileSpreadsheet className="w-5 h-5 text-green-600" />
                <div>
                  <h2 id="import-modal-title" className="text-lg font-semibold text-gray-900 dark:text-white">Import Preview</h2>
                  <p className="text-xs text-gray-500">Values will REPLACE existing data (Platinum shows cumulative totals)</p>
                </div>
              </div>
              <button
                onClick={() => { setShowImportModal(false); setImportPreview([]); }}
                aria-label="Close import preview"
                className="p-1 hover:bg-gray-100 dark:hover:bg-gray-700 rounded"
              >
                <X className="w-5 h-5 text-gray-500" />
              </button>
            </div>

            <div className="p-6 overflow-y-auto max-h-[calc(90vh-180px)]">
              {importError && (
                <div className={`mb-4 p-3 rounded-lg flex items-start gap-2 ${
                  importError.includes('failed') || importError.includes('skipped')
                    ? 'bg-yellow-50 dark:bg-yellow-900/20 text-yellow-700 dark:text-yellow-400'
                    : 'bg-red-50 dark:bg-red-900/20 text-red-700 dark:text-red-400'
                }`}>
                  <AlertTriangle className="w-4 h-4 mt-0.5 flex-shrink-0" />
                  <div className="text-sm">{importError}</div>
                </div>
              )}

              <div className="mb-4 flex flex-wrap gap-4">
                <div className="flex items-center gap-2 text-sm">
                  <CheckCircle2 className="w-4 h-4 text-green-600" />
                  <span className="text-gray-600 dark:text-gray-400">{matchedCount} matched</span>
                </div>
                {importPreview.filter(r => r.isInactive && r.matchedStudent).length > 0 && (
                  <div className="flex items-center gap-2 text-sm bg-gray-50 dark:bg-gray-700/50 px-3 py-1 rounded-lg">
                    <X className="w-4 h-4 text-gray-500" />
                    <span className="text-gray-600 dark:text-gray-400 font-medium">
                      {importPreview.filter(r => r.isInactive && r.matchedStudent).length} will be marked inactive
                    </span>
                  </div>
                )}
                {unmatchedCount > 0 && (
                  <div className="flex items-center gap-2 text-sm bg-yellow-50 dark:bg-yellow-900/20 px-3 py-1 rounded-lg">
                    <AlertTriangle className="w-4 h-4 text-yellow-600" />
                    <span className="text-yellow-700 dark:text-yellow-400 font-medium">
                      {unmatchedCount} unmatched - select from dropdown or will be skipped
                    </span>
                  </div>
                )}
              </div>

              <div className="overflow-x-auto border rounded-lg border-gray-200 dark:border-gray-700">
                <table className="w-full text-sm">
                  <thead className="bg-gray-50 dark:bg-gray-700">
                    <tr>
                      <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 dark:text-gray-400">Status</th>
                      <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 dark:text-gray-400">Name (from file)</th>
                      <th className="px-3 py-2 text-left text-xs font-medium text-gray-500 dark:text-gray-400">Matched To</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">Psych</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">ED</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">Elective</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">ICU</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">OB</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">OR</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">Peds ED</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">Peds ICU</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">CCL</th>
                      <th className="px-3 py-2 text-center text-xs font-medium text-gray-500 dark:text-gray-400">EMS</th>
                    </tr>
                  </thead>
                  <tbody className="divide-y divide-gray-200 dark:divide-gray-700">
                    {/* Show unmatched rows first, then inactive, then matched */}
                    {importPreview
                      .map((row, idx) => ({ row, idx }))
                      .sort((a, b) => {
                        // Unmatched first, then inactive, then matched active
                        const aScore = !a.row.matchedStudent ? 0 : a.row.isInactive ? 1 : 2;
                        const bScore = !b.row.matchedStudent ? 0 : b.row.isInactive ? 1 : 2;
                        return aScore - bScore;
                      })
                      .map(({ row, idx }) => (
                      <tr
                        key={idx}
                        className={
                          !row.matchedStudent
                            ? 'bg-yellow-50 dark:bg-yellow-900/10'
                            : row.isInactive
                            ? 'bg-gray-50 dark:bg-gray-700/30 opacity-70'
                            : ''
                        }
                      >
                        <td className="px-3 py-2">
                          {row.isInactive && row.matchedStudent ? (
                            <span className="inline-flex items-center px-1.5 py-0.5 rounded text-xs font-medium bg-gray-200 dark:bg-gray-600 text-gray-600 dark:text-gray-300">
                              Inactive
                            </span>
                          ) : row.matchedStudent ? (
                            <CheckCircle2 className="w-4 h-4 text-green-600" />
                          ) : (
                            <AlertTriangle className="w-4 h-4 text-yellow-600" />
                          )}
                        </td>
                        <td className="px-3 py-2 text-gray-900 dark:text-white font-medium">{row.name}</td>
                        <td className="px-3 py-2 min-w-[200px]">
                          {row.matchedStudent ? (
                            <span className={row.isInactive ? 'text-gray-500 dark:text-gray-400' : 'text-green-700 dark:text-green-400'}>
                              <span className={row.isInactive ? 'line-through' : ''}>
                                {row.matchedStudent.first_name} {row.matchedStudent.last_name}
                              </span>
                              {row.manualMatch && <span className="text-xs ml-1">(manual)</span>}
                              {row.isInactive && <span className="text-xs ml-1 text-gray-500 dark:text-gray-400">(will be marked inactive)</span>}
                            </span>
                          ) : (
                            <div className="space-y-1">
                              <select
                                value={row.manualMatch || ''}
                                onChange={(e) => handleManualMatch(idx, e.target.value)}
                                className="w-full text-xs px-2 py-1 border rounded bg-white dark:bg-gray-700 border-yellow-400 dark:border-yellow-600 text-gray-900 dark:text-white"
                              >
                                <option value="">-- Select student --</option>
                                {row.similarNames.length > 0 && (
                                  <optgroup label="Similar names">
                                    {row.similarNames.map(name => {
                                      const student = students.find(s => `${s.first_name} ${s.last_name}` === name);
                                      return student ? (
                                        <option key={student.id} value={student.id}>
                                          {name}
                                        </option>
                                      ) : null;
                                    })}
                                  </optgroup>
                                )}
                                <optgroup label="All students">
                                  {students.map(s => (
                                    <option key={s.id} value={s.id}>
                                      {s.first_name} {s.last_name}
                                    </option>
                                  ))}
                                </optgroup>
                              </select>
                              {row.similarNames.length > 0 && !row.manualMatch && (
                                <div className="text-xs text-yellow-600 dark:text-yellow-400">
                                  Similar: {row.similarNames.join(', ')}
                                </div>
                              )}
                            </div>
                          )}
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.psych_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.ed_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.ems_field_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.icu_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.ob_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.or_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.peds_ed_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.peds_icu_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.cardiology_hours || 0}h
                        </td>
                        <td className="px-3 py-2 text-center text-xs">
                          {row.data.ems_ridealong_hours || 0}h
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>

            <div className="px-6 py-4 border-t border-gray-200 dark:border-gray-700 flex justify-end gap-3">
              <button
                onClick={() => { setShowImportModal(false); setImportPreview([]); }}
                className="px-4 py-2 text-gray-700 dark:text-gray-300 hover:bg-gray-100 dark:hover:bg-gray-700 rounded-lg"
              >
                Cancel
              </button>
              <button
                onClick={executeImport}
                disabled={importing || matchedCount === 0}
                className="flex items-center gap-2 px-4 py-2 bg-green-600 text-white rounded-lg hover:bg-green-700 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
              >
                {importing ? (
                  <>
                    <Loader2 className="w-4 h-4 animate-spin" />
                    Importing...
                  </>
                ) : (
                  <>
                    <Upload className="w-4 h-4" />
                    {(() => {
                      const activeCount = importPreview.filter(r => r.matchedStudent && !r.isInactive).length;
                      const inactiveCount = importPreview.filter(r => r.matchedStudent && r.isInactive).length;
                      if (activeCount > 0 && inactiveCount > 0) return `Import ${activeCount}, Mark ${inactiveCount} Inactive`;
                      if (inactiveCount > 0) return `Mark ${inactiveCount} Inactive`;
                      return `Import ${activeCount} Student${activeCount !== 1 ? 's' : ''}`;
                    })()}
                  </>
                )}
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
}
